#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        if ((N == 2 && M == 1)) {
            printf("1 2\n");
        } else if (N >= 3 && M == N) {
            for (int i = 1; i < N; ++i) {
                printf("%d %d\n", i, i + 1);
            }
            printf("%d 1\n", N);
        } else {
            printf("-1 -1\n");
        }
    }
    return 0;
}

