import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        if N == 2 and M == 1:
            out_lines.append('1 2')
        elif N >= 3 and M == N:
            for i in range(1, N):
                out_lines.append(f"{i} {i+1}")
            out_lines.append(f"{N} 1")
        else:
            out_lines.append('-1 -1')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

